let dotNetRef = null;
let resizeHandler = null;

function getCategory(width) {
    if (width < 768) return "Mobile";
    if (width < 1024) return "Tablet";
    return "Desktop";
}

export function initialize(ref) {
    dotNetRef = ref;
    let currentCategory = getCategory(window.innerWidth);
    dotNetRef.invokeMethodAsync("OnViewportCategoryChanged", currentCategory);

    resizeHandler = () => {
        const newCategory = getCategory(window.innerWidth);
        if (newCategory !== currentCategory) {
            currentCategory = newCategory;
            dotNetRef.invokeMethodAsync("OnViewportCategoryChanged", newCategory);
        }
    };

    window.addEventListener("resize", resizeHandler);
}

export function dispose() {
    if (resizeHandler) {
        window.removeEventListener("resize", resizeHandler);
        resizeHandler = null;
    }
    dotNetRef = null;
}

